mapper.select:
SELECT id, app_code, address, machine_tag, status, last_heartbeat_time, meta_json, create_time, update_time
FROM executor_node
WHERE app_code = #{appCode}
  AND address = #{address}

mapper.insert:
INSERT INTO executor_node (
    app_code, address, machine_tag, status, last_heartbeat_time, meta_json, create_time, update_time
) VALUES (
    #{appCode}, #{address}, #{machineTag}, #{status}, #{lastHeartbeatTime}, #{metaJson}, NOW(), NOW()
)
